package generator

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/reliant-labs/forge/internal/config"
	"github.com/reliant-labs/forge/internal/naming"
)

// GeneratePlanORM writes internal/db/<snake_name>_orm.go for each entity
// defined in the plan. The generated files provide standalone CRUD functions
// and a private scan helper. Because entity types are type aliases (defined
// in internal/db/types.go), we cannot attach methods to them — everything
// is a package-level function.
func GeneratePlanORM(root, modulePath, serviceName string, entities []config.PlanEntity) error {
	if len(entities) == 0 {
		return nil
	}

	dbDir := filepath.Join(root, "internal", "db")
	if err := os.MkdirAll(dbDir, 0o755); err != nil {
		return fmt.Errorf("create db directory: %w", err)
	}

	// Clean up stale ORM files for entities that no longer exist.
	expectedFiles := make(map[string]bool)
	expectedFiles["orm_shared.go"] = true
	expectedFiles["types.go"] = true
	for _, ent := range entities {
		expectedFiles[naming.ToSnakeCase(ent.Name)+"_orm.go"] = true
	}
	existing, _ := os.ReadDir(dbDir)
	for _, e := range existing {
		if !e.IsDir() && strings.HasSuffix(e.Name(), "_orm.go") && !expectedFiles[e.Name()] {
			os.Remove(filepath.Join(dbDir, e.Name()))
		}
	}

	// Write ormTracer var in a shared file (one per project).
	if err := writeORMShared(dbDir); err != nil {
		return fmt.Errorf("write orm shared: %w", err)
	}

	for _, ent := range entities {
		if err := writeORMEntity(dbDir, modulePath, serviceName, ent); err != nil {
			return fmt.Errorf("generate ORM for entity %s: %w", ent.Name, err)
		}
	}
	return nil
}

// writeORMShared creates the shared orm_shared.go with the ormTracer var.
func writeORMShared(dbDir string) error {
	var b strings.Builder
	b.WriteString("// Code generated by forge. DO NOT EDIT.\n")
	b.WriteString("package db\n\n")
	b.WriteString("import (\n")
	b.WriteString("\t\"go.opentelemetry.io/otel\"\n")
	b.WriteString(")\n\n")
	b.WriteString("var ormTracer = otel.Tracer(\"orm\")\n")
	return os.WriteFile(filepath.Join(dbDir, "orm_shared.go"), []byte(b.String()), 0o644)
}

// ormField holds the resolved metadata for a single entity field used during
// code generation. This mirrors the information in the protoc-based codegen's
// fieldInfo but is derived directly from PlanEntityField.
type ormField struct {
	planField   config.PlanEntityField
	goName      string // PascalCase Go field name (proto-style)
	columnName  string // snake_case column name
	goType      string // Go type for Values/Scan
	ormType     string // orm.TypeXxx constant name
	isTimestamp bool
	isPK        bool
	isTenantKey bool
	notNull     bool
	unique      bool
	references  string
	nullable    bool // should scan as pointer
}

func writeORMEntity(dbDir, modulePath, serviceName string, ent config.PlanEntity) error {
	msgName := ent.Name
	tableName := ent.TableName
	if tableName == "" {
		tableName = naming.Pluralize(naming.ToSnakeCase(ent.Name))
	}

	// Build fields list including auto-generated timestamp/soft-delete fields.
	fields := resolveORMFields(ent)

	// Identify special fields.
	var pkField *ormField
	var tenantField *ormField
	for i := range fields {
		if fields[i].isPK {
			pkField = &fields[i]
		}
		if fields[i].isTenantKey {
			tenantField = &fields[i]
		}
	}

	pkCol := "id"
	pkGoType := "string"
	if pkField != nil {
		pkCol = pkField.columnName
		pkGoType = pkField.goType
	}

	hasTenant := tenantField != nil
	hasTimestamp := false
	for _, f := range fields {
		if f.isTimestamp {
			hasTimestamp = true
			break
		}
	}

	var b strings.Builder

	// Header
	b.WriteString("// Code generated by forge. DO NOT EDIT.\n")
	b.WriteString("package db\n\n")

	// Imports
	writeORMImports(&b, hasTimestamp, ent.SoftDelete, hasTenant)

	// Field name constants
	fmt.Fprintf(&b, "// Field name constants for %s.\n", msgName)
	fmt.Fprintf(&b, "const %sTableName = %q\n\n", msgName, tableName)
	b.WriteString("const (\n")
	for _, f := range fields {
		fmt.Fprintf(&b, "\t%sField%s = %q\n", msgName, f.goName, f.columnName)
	}
	b.WriteString(")\n\n")

	// Column list helper (package-level var for the ordered column list)
	lowerMsg := strings.ToLower(msgName[:1]) + msgName[1:]
	fmt.Fprintf(&b, "// %sColumns is the ordered list of columns for %s.\n", lowerMsg, msgName)
	fmt.Fprintf(&b, "var %sColumns = []string{\n", lowerMsg)
	for _, f := range fields {
		fmt.Fprintf(&b, "\t%q,\n", f.columnName)
	}
	b.WriteString("}\n\n")

	// scan function
	writeORMScanFunc(&b, msgName, lowerMsg, fields)

	// CRUD functions
	writeORMCreate(&b, msgName, tableName, lowerMsg, fields, hasTenant, tenantField, pkField)
	writeORMGetByID(&b, msgName, tableName, lowerMsg, pkCol, pkGoType, hasTenant, ent.SoftDelete)
	writeORMList(&b, msgName, tableName, lowerMsg, hasTenant, ent.SoftDelete, tenantField)
	writeORMCount(&b, msgName, tableName, hasTenant, ent.SoftDelete, tenantField)
	if ent.SoftDelete {
		writeORMListAll(&b, msgName, tableName, lowerMsg, hasTenant, tenantField)
	}
	writeORMUpdate(&b, msgName, tableName, lowerMsg, pkCol, fields, hasTenant, ent.SoftDelete, tenantField, pkField)
	writeORMDelete(&b, msgName, tableName, pkCol, pkGoType, fields, hasTenant, ent.SoftDelete, tenantField)

	fileName := naming.ToSnakeCase(ent.Name) + "_orm.go"
	return os.WriteFile(filepath.Join(dbDir, fileName), []byte(b.String()), 0o644)
}

func writeORMImports(b *strings.Builder, hasTimestamp, softDelete, hasTenant bool) {
	b.WriteString("import (\n")
	b.WriteString("\t\"context\"\n")
	if hasTimestamp {
		b.WriteString("\t\"database/sql\"\n")
	}
	b.WriteString("\t\"fmt\"\n")
	b.WriteString("\t\"strings\"\n")
	b.WriteString("\n")
	b.WriteString("\t\"github.com/reliant-labs/forge/pkg/orm\"\n")
	b.WriteString("\t\"go.opentelemetry.io/otel/attribute\"\n")
	b.WriteString("\t\"go.opentelemetry.io/otel/codes\"\n")
	b.WriteString("\t\"go.opentelemetry.io/otel/trace\"\n")
	if hasTimestamp {
		b.WriteString("\t\"google.golang.org/protobuf/types/known/timestamppb\"\n")
	}
	b.WriteString(")\n\n")
}

// writeORMScanFunc writes a standalone scan<Entity> function.
func writeORMScanFunc(b *strings.Builder, msgName, lowerMsg string, fields []ormField) {
	fmt.Fprintf(b, "// scan%s scans a database row into a %s.\n", msgName, msgName)
	fmt.Fprintf(b, "func scan%s(scanner interface{ Scan(...interface{}) error }) (*%s, error) {\n", msgName, msgName)
	fmt.Fprintf(b, "\tentity := &%s{}\n", msgName)

	// Declare temp variables for timestamps and nullable fields.
	hasTemps := false
	for _, f := range fields {
		if f.isTimestamp || f.nullable {
			hasTemps = true
			break
		}
	}
	if hasTemps {
		b.WriteString("\tvar (\n")
		for _, f := range fields {
			if f.isTimestamp {
				fmt.Fprintf(b, "\t\tdb%s sql.NullTime\n", f.goName)
			} else if f.nullable {
				fmt.Fprintf(b, "\t\tdb%s *%s\n", f.goName, f.goType)
			}
		}
		b.WriteString("\t)\n\n")
	}

	// Scan call
	b.WriteString("\terr := scanner.Scan(\n")
	for _, f := range fields {
		if f.isTimestamp {
			fmt.Fprintf(b, "\t\t&db%s,\n", f.goName)
		} else if f.nullable {
			fmt.Fprintf(b, "\t\t&db%s,\n", f.goName)
		} else {
			fmt.Fprintf(b, "\t\t&entity.%s,\n", f.goName)
		}
	}
	b.WriteString("\t)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\treturn nil, err\n")
	b.WriteString("\t}\n\n")

	// Assignment for timestamps and nullable fields
	for _, f := range fields {
		if f.isTimestamp {
			fmt.Fprintf(b, "\tif db%s.Valid {\n", f.goName)
			fmt.Fprintf(b, "\t\tentity.%s = timestamppb.New(db%s.Time)\n", f.goName, f.goName)
			b.WriteString("\t}\n")
		} else if f.nullable {
			fmt.Fprintf(b, "\tif db%s != nil {\n", f.goName)
			fmt.Fprintf(b, "\t\tentity.%s = *db%s\n", f.goName, f.goName)
			b.WriteString("\t}\n")
		}
	}

	b.WriteString("\n\treturn entity, nil\n")
	b.WriteString("}\n\n")
}

func writeORMCreate(b *strings.Builder, msgName, tableName, lowerMsg string, fields []ormField, hasTenant bool, tenantField *ormField, pkField *ormField) {
	fmt.Fprintf(b, "// Create%s inserts a new %s row into the database.\n", msgName, msgName)
	if hasTenant {
		fmt.Fprintf(b, "func Create%s(ctx context.Context, db orm.Context, msg *%s, tenantID string) error {\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "func Create%s(ctx context.Context, db orm.Context, msg *%s) error {\n", msgName, msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Create%s\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	if hasTenant && tenantField != nil {
		b.WriteString("\t// Enforce tenant isolation: set tenant field from caller.\n")
		fmt.Fprintf(b, "\tmsg.%s = tenantID\n\n", tenantField.goName)
	}

	// Build column list and placeholders for INSERT
	b.WriteString("\tdialect := db.Dialect()\n")

	// Build columns and values
	b.WriteString("\tcolumns := []string{\n")
	for _, f := range fields {
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", f.columnName)
	}
	b.WriteString("\t}\n")

	b.WriteString("\tplaceholders := make([]string, len(columns))\n")
	b.WriteString("\tfor i := range columns {\n")
	b.WriteString("\t\tplaceholders[i] = dialect.Placeholder(i)\n")
	b.WriteString("\t}\n\n")

	// Build values slice
	b.WriteString("\tvalues := []any{\n")
	for _, f := range fields {
		accessor := "msg." + f.goName
		if f.isTimestamp {
			fmt.Fprintf(b, "\t\tfunc() any { if %s != nil { return %s.AsTime() }; return nil }(),\n", accessor, accessor)
		} else {
			fmt.Fprintf(b, "\t\t%s,\n", accessor)
		}
	}
	b.WriteString("\t}\n\n")

	// Build INSERT with ON CONFLICT (upsert)
	// Find PK column name for conflict clause
	pkColName := "id"
	if pkField != nil {
		pkColName = pkField.columnName
	}

	b.WriteString("\tquery := fmt.Sprintf(\"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT (%s) DO UPDATE SET %s\",\n")
	fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
	b.WriteString("\t\tstrings.Join(columns, \", \"),\n")
	b.WriteString("\t\tstrings.Join(placeholders, \", \"),\n")
	fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkColName)

	// Build SET clause for upsert: exclude PK
	b.WriteString("\t\tfunc() string {\n")
	b.WriteString("\t\t\tvar sets []string\n")
	idx := len(fields) // start placeholders after INSERT values
	for _, f := range fields {
		if f.isPK {
			continue
		}
		fmt.Fprintf(b, "\t\t\tsets = append(sets, fmt.Sprintf(\"%%s = %%s\", dialect.QuoteIdentifier(%q), dialect.Placeholder(%d)))\n", f.columnName, idx)
		idx++
	}
	b.WriteString("\t\t\treturn strings.Join(sets, \", \")\n")
	b.WriteString("\t\t}(),\n")
	b.WriteString("\t)\n\n")

	// Build upsert args: INSERT values + UPDATE values (excluding PK)
	b.WriteString("\t// Append update values (excludes PK) for the ON CONFLICT SET clause.\n")
	b.WriteString("\tupsertArgs := make([]any, 0, len(values)*2)\n")
	b.WriteString("\tupsertArgs = append(upsertArgs, values...)\n")
	b.WriteString("\tfor i, col := range columns {\n")
	fmt.Fprintf(b, "\t\tif col == dialect.QuoteIdentifier(%q) {\n", pkColName)
	b.WriteString("\t\t\tcontinue\n")
	b.WriteString("\t\t}\n")
	b.WriteString("\t\t_ = col\n")
	b.WriteString("\t\tupsertArgs = append(upsertArgs, values[i])\n")
	b.WriteString("\t}\n\n")

	b.WriteString("\t_, err := db.Exec(ctx, query, upsertArgs...)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn fmt.Errorf(\"create %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn nil\n")
	b.WriteString("}\n\n")
}

func writeORMGetByID(b *strings.Builder, msgName, tableName, lowerMsg, pkCol, pkGoType string, hasTenant, softDelete bool) {
	fmt.Fprintf(b, "// Get%sByID retrieves a %s by its primary key.\n", msgName, msgName)
	if hasTenant {
		fmt.Fprintf(b, "func Get%sByID(ctx context.Context, db orm.Context, id %s, tenantID string) (*%s, error) {\n", msgName, pkGoType, msgName)
	} else {
		fmt.Fprintf(b, "func Get%sByID(ctx context.Context, db orm.Context, id %s) (*%s, error) {\n", msgName, pkGoType, msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Get%sByID\",\n", msgName)
	b.WriteString("\t\ttrace.WithAttributes(\n")
	fmt.Fprintf(b, "\t\t\tattribute.String(\"table\", %q),\n", tableName)
	b.WriteString("\t\t\tattribute.String(\"id\", fmt.Sprint(id)),\n")
	b.WriteString("\t\t))\n")
	b.WriteString("\tdefer span.End()\n\n")

	if softDelete || hasTenant {
		// Use List with filters for soft-delete and/or tenant scoping.
		if hasTenant {
			fmt.Fprintf(b, "\tresults, err := List%s(ctx, db, tenantID, orm.WhereEq(%q, id), orm.WithLimit(1))\n", msgName, pkCol)
		} else {
			fmt.Fprintf(b, "\tresults, err := List%s(ctx, db, orm.WhereEq(%q, id), orm.WithLimit(1))\n", msgName, pkCol)
		}
		b.WriteString("\tif err != nil {\n")
		b.WriteString("\t\tspan.RecordError(err)\n")
		b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
		b.WriteString("\t\treturn nil, err\n")
		b.WriteString("\t}\n")
		b.WriteString("\tif len(results) == 0 {\n")
		fmt.Fprintf(b, "\t\treturn nil, fmt.Errorf(\"get %s by id: not found\")\n", tableName)
		b.WriteString("\t}\n")
		b.WriteString("\treturn results[0], nil\n")
	} else {
		// Simple case: direct query by PK.
		fmt.Fprintf(b, "\tqb := orm.NewQueryBuilder(db, %q, %sColumns)\n", tableName, lowerMsg)
		fmt.Fprintf(b, "\tqb.Where(%q, orm.Eq, id)\n", pkCol)
		b.WriteString("\tqb.Limit(1)\n")
		b.WriteString("\tquery, args := qb.Build()\n")
		b.WriteString("\trow := db.QueryRow(ctx, query, args...)\n")
		fmt.Fprintf(b, "\tentity, err := scan%s(row)\n", msgName)
		b.WriteString("\tif err != nil {\n")
		b.WriteString("\t\tspan.RecordError(err)\n")
		b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
		fmt.Fprintf(b, "\t\treturn nil, fmt.Errorf(\"get %s by id: %%w\", err)\n", tableName)
		b.WriteString("\t}\n")
		b.WriteString("\treturn entity, nil\n")
	}
	b.WriteString("}\n\n")
}

func writeORMList(b *strings.Builder, msgName, tableName, lowerMsg string, hasTenant, softDelete bool, tenantField *ormField) {
	fmt.Fprintf(b, "// List%s retrieves %s rows with optional filtering.\n", msgName, msgName)
	if hasTenant {
		fmt.Fprintf(b, "func List%s(ctx context.Context, db orm.Context, tenantID string, opts ...orm.QueryOption) ([]*%s, error) {\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "func List%s(ctx context.Context, db orm.Context, opts ...orm.QueryOption) ([]*%s, error) {\n", msgName, msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.List%s\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	if hasTenant && tenantField != nil {
		b.WriteString("\t// Prepend tenant isolation filter.\n")
		fmt.Fprintf(b, "\topts = append([]orm.QueryOption{orm.WhereEq(%q, tenantID)}, opts...)\n\n", tenantField.columnName)
	}

	if softDelete {
		b.WriteString("\t// Prepend soft-delete filter.\n")
		b.WriteString("\topts = append([]orm.QueryOption{orm.WhereIsNull(\"deleted_at\")}, opts...)\n\n")
	}

	fmt.Fprintf(b, "\tqb := orm.NewQueryBuilder(db, %q, %sColumns)\n", tableName, lowerMsg)
	b.WriteString("\tfor _, opt := range opts {\n")
	b.WriteString("\t\topt(qb)\n")
	b.WriteString("\t}\n\n")

	b.WriteString("\trows, err := qb.Execute(ctx)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn nil, fmt.Errorf(\"list %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\tdefer rows.Close()\n\n")

	b.WriteString("\tvar results []*" + msgName + "\n")
	b.WriteString("\tfor rows.Next() {\n")
	fmt.Fprintf(b, "\t\tentity, err := scan%s(rows)\n", msgName)
	b.WriteString("\t\tif err != nil {\n")
	b.WriteString("\t\t\tspan.RecordError(err)\n")
	b.WriteString("\t\t\tspan.SetStatus(codes.Error, err.Error())\n")
	b.WriteString("\t\t\treturn nil, err\n")
	b.WriteString("\t\t}\n")
	b.WriteString("\t\tresults = append(results, entity)\n")
	b.WriteString("\t}\n")
	b.WriteString("\tif err := rows.Err(); err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn nil, fmt.Errorf(\"list %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn results, nil\n")
	b.WriteString("}\n\n")
}

func writeORMCount(b *strings.Builder, msgName, tableName string, hasTenant, softDelete bool, tenantField *ormField) {
	fmt.Fprintf(b, "// Count%s returns the number of matching %s rows.\n", msgName, msgName)
	if hasTenant {
		fmt.Fprintf(b, "func Count%s(ctx context.Context, db orm.Context, tenantID string, opts ...orm.QueryOption) (int64, error) {\n", msgName)
	} else {
		fmt.Fprintf(b, "func Count%s(ctx context.Context, db orm.Context, opts ...orm.QueryOption) (int64, error) {\n", msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Count%s\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	if hasTenant && tenantField != nil {
		fmt.Fprintf(b, "\topts = append([]orm.QueryOption{orm.WhereEq(%q, tenantID)}, opts...)\n\n", tenantField.columnName)
	}

	if softDelete {
		b.WriteString("\topts = append([]orm.QueryOption{orm.WhereIsNull(\"deleted_at\")}, opts...)\n\n")
	}

	fmt.Fprintf(b, "\tqb := orm.NewQueryBuilder(db, %q, []string{\"COUNT(*)\"})\n", tableName)
	b.WriteString("\tfor _, opt := range opts {\n")
	b.WriteString("\t\topt(qb)\n")
	b.WriteString("\t}\n\n")

	b.WriteString("\tquery, args := qb.Build()\n")
	b.WriteString("\trow := db.QueryRow(ctx, query, args...)\n\n")
	b.WriteString("\tvar count int64\n")
	b.WriteString("\tif err := row.Scan(&count); err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn 0, fmt.Errorf(\"count %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn count, nil\n")
	b.WriteString("}\n\n")
}

func writeORMListAll(b *strings.Builder, msgName, tableName, lowerMsg string, hasTenant bool, tenantField *ormField) {
	fmt.Fprintf(b, "// ListAll%s retrieves all %s rows including soft-deleted ones.\n", msgName, msgName)
	if hasTenant {
		fmt.Fprintf(b, "func ListAll%s(ctx context.Context, db orm.Context, tenantID string, opts ...orm.QueryOption) ([]*%s, error) {\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "func ListAll%s(ctx context.Context, db orm.Context, opts ...orm.QueryOption) ([]*%s, error) {\n", msgName, msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.ListAll%s\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	if hasTenant && tenantField != nil {
		b.WriteString("\t// Tenant isolation still applies even for ListAll (bypasses soft-delete only).\n")
		fmt.Fprintf(b, "\topts = append([]orm.QueryOption{orm.WhereEq(%q, tenantID)}, opts...)\n\n", tenantField.columnName)
	}

	fmt.Fprintf(b, "\tqb := orm.NewQueryBuilder(db, %q, %sColumns)\n", tableName, lowerMsg)
	b.WriteString("\tfor _, opt := range opts {\n")
	b.WriteString("\t\topt(qb)\n")
	b.WriteString("\t}\n\n")

	b.WriteString("\trows, err := qb.Execute(ctx)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn nil, fmt.Errorf(\"list all %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\tdefer rows.Close()\n\n")

	b.WriteString("\tvar results []*" + msgName + "\n")
	b.WriteString("\tfor rows.Next() {\n")
	fmt.Fprintf(b, "\t\tentity, err := scan%s(rows)\n", msgName)
	b.WriteString("\t\tif err != nil {\n")
	b.WriteString("\t\t\treturn nil, err\n")
	b.WriteString("\t\t}\n")
	b.WriteString("\t\tresults = append(results, entity)\n")
	b.WriteString("\t}\n")
	b.WriteString("\tif err := rows.Err(); err != nil {\n")
	fmt.Fprintf(b, "\t\treturn nil, fmt.Errorf(\"list all %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn results, nil\n")
	b.WriteString("}\n\n")
}

func writeORMUpdate(b *strings.Builder, msgName, tableName, lowerMsg, pkCol string, fields []ormField, hasTenant, softDelete bool, tenantField *ormField, pkField *ormField) {
	// Count updatable fields (excluding PK, deleted_at, tenant key).
	updatableCount := 0
	for _, f := range fields {
		if f.isPK || f.columnName == "deleted_at" || f.isTenantKey {
			continue
		}
		updatableCount++
	}

	// If there are no updatable fields, generate a no-op function.
	if updatableCount == 0 {
		fmt.Fprintf(b, "// Update%s is a no-op because %s has no updatable fields.\n", msgName, msgName)
		if hasTenant {
			fmt.Fprintf(b, "func Update%s(_ context.Context, _ orm.Context, _ *%s, _ string) error {\n", msgName, msgName)
		} else {
			fmt.Fprintf(b, "func Update%s(_ context.Context, _ orm.Context, _ *%s) error {\n", msgName, msgName)
		}
		b.WriteString("\treturn nil // no updatable fields\n")
		b.WriteString("}\n\n")
		return
	}

	fmt.Fprintf(b, "// Update%s updates an existing %s by its primary key.\n", msgName, msgName)
	if hasTenant {
		fmt.Fprintf(b, "func Update%s(ctx context.Context, db orm.Context, msg *%s, tenantID string) error {\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "func Update%s(ctx context.Context, db orm.Context, msg *%s) error {\n", msgName, msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Update%s\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	b.WriteString("\tdialect := db.Dialect()\n\n")

	// Build SET clause excluding PK, deleted_at, and tenant columns.
	type setCol struct {
		field ormField
		idx   int
	}
	var setCols []setCol
	for i, f := range fields {
		if f.isPK || f.columnName == "deleted_at" || f.isTenantKey {
			continue
		}
		setCols = append(setCols, setCol{field: f, idx: i})
	}

	b.WriteString("\tsetParts := []string{\n")
	for phIdx, sc := range setCols {
		fmt.Fprintf(b, "\t\tfmt.Sprintf(\"%%s = %%s\", dialect.QuoteIdentifier(%q), dialect.Placeholder(%d)),\n", sc.field.columnName, phIdx)
	}
	b.WriteString("\t}\n\n")

	// Build values for SET clause
	b.WriteString("\targs := []any{\n")
	for _, sc := range setCols {
		accessor := "msg." + sc.field.goName
		if sc.field.isTimestamp {
			fmt.Fprintf(b, "\t\tfunc() any { if %s != nil { return %s.AsTime() }; return nil }(),\n", accessor, accessor)
		} else {
			fmt.Fprintf(b, "\t\t%s,\n", accessor)
		}
	}
	b.WriteString("\t}\n\n")

	pkPlaceholderIdx := len(setCols)

	if softDelete && hasTenant {
		tenantPlaceholderIdx := pkPlaceholderIdx + 1
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s IS NULL AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", tenantPlaceholderIdx)
		b.WriteString("\t)\n\n")
		// Append PK and tenant values
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s, tenantID)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id, tenantID)\n")
		}
	} else if softDelete {
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s IS NULL\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		b.WriteString("\t)\n\n")
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id)\n")
		}
	} else if hasTenant {
		tenantPlaceholderIdx := pkPlaceholderIdx + 1
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", tenantPlaceholderIdx)
		b.WriteString("\t)\n\n")
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s, tenantID)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id, tenantID)\n")
		}
	} else {
		// Simple case: no soft-delete, no tenant.
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		b.WriteString("\t)\n\n")
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id)\n")
		}
	}

	b.WriteString("\n\t_, err := db.Exec(ctx, query, args...)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn fmt.Errorf(\"update %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn nil\n")
	b.WriteString("}\n\n")
}

func writeORMDelete(b *strings.Builder, msgName, tableName, pkCol, pkGoType string, fields []ormField, hasTenant, softDelete bool, tenantField *ormField) {
	if softDelete {
		fmt.Fprintf(b, "// Delete%s soft-deletes a %s by setting deleted_at.\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "// Delete%s permanently deletes a %s by its primary key.\n", msgName, msgName)
	}
	if hasTenant {
		fmt.Fprintf(b, "func Delete%s(ctx context.Context, db orm.Context, id %s, tenantID string) error {\n", msgName, pkGoType)
	} else {
		fmt.Fprintf(b, "func Delete%s(ctx context.Context, db orm.Context, id %s) error {\n", msgName, pkGoType)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Delete%s\",\n", msgName)
	b.WriteString("\t\ttrace.WithAttributes(\n")
	fmt.Fprintf(b, "\t\t\tattribute.String(\"table\", %q),\n", tableName)
	b.WriteString("\t\t\tattribute.String(\"id\", fmt.Sprint(id)),\n")
	b.WriteString("\t\t))\n")
	b.WriteString("\tdefer span.End()\n\n")

	if softDelete && hasTenant {
		b.WriteString("\t// Soft delete with tenant isolation.\n")
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s = CURRENT_TIMESTAMP WHERE %s = %s AND %s IS NULL AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		b.WriteString("\t\tdialect.Placeholder(1),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id, tenantID)\n")
	} else if softDelete {
		b.WriteString("\t// Soft delete: set deleted_at instead of removing the row.\n")
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s = CURRENT_TIMESTAMP WHERE %s = %s AND %s IS NULL\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id)\n")
	} else if hasTenant {
		b.WriteString("\t// Hard delete with tenant isolation.\n")
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"DELETE FROM %s WHERE %s = %s AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		b.WriteString("\t\tdialect.Placeholder(1),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id, tenantID)\n")
	} else {
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"DELETE FROM %s WHERE %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id)\n")
	}

	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn fmt.Errorf(\"delete %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn nil\n")
	b.WriteString("}\n")
}

// resolveORMFields converts PlanEntity fields (including auto-generated
// timestamp/soft-delete fields) into the ormField representation used
// by the code generator.
func resolveORMFields(ent config.PlanEntity) []ormField {
	type entry struct {
		config.PlanEntityField
		autoGenerated bool
	}

	// Check if any field already serves as the primary key.
	hasPK := false
	for _, f := range ent.Fields {
		if f.PrimaryKey || f.Name == "id" {
			hasPK = true
			break
		}
	}

	entries := make([]entry, 0, len(ent.Fields)+4)

	// Auto-add an id primary key field if none exists.
	if !hasPK {
		entries = append(entries, entry{PlanEntityField: config.PlanEntityField{
			Name: "id", Type: "string", PrimaryKey: true, NotNull: true,
		}})
	}

	for _, f := range ent.Fields {
		entries = append(entries, entry{PlanEntityField: f})
	}

	if ent.Timestamps {
		entries = append(entries,
			entry{PlanEntityField: config.PlanEntityField{Name: "created_at", Type: "google.protobuf.Timestamp"}, autoGenerated: true},
			entry{PlanEntityField: config.PlanEntityField{Name: "updated_at", Type: "google.protobuf.Timestamp"}, autoGenerated: true},
		)
	}
	if ent.SoftDelete {
		entries = append(entries,
			entry{PlanEntityField: config.PlanEntityField{Name: "deleted_at", Type: "google.protobuf.Timestamp"}, autoGenerated: true},
		)
	}

	fields := make([]ormField, 0, len(entries))
	for _, e := range entries {
		f := ormField{
			planField:   e.PlanEntityField,
			goName:      naming.ToProtoPascalCase(e.Name),
			columnName:  e.Name,
			goType:      planFieldGoType(e.Type),
			ormType:     planFieldOrmType(e.Type),
			isTimestamp: e.Type == "google.protobuf.Timestamp" || e.Type == "timestamp",
			isPK:        e.PrimaryKey,
			isTenantKey: e.TenantKey,
			notNull:     e.NotNull,
			unique:      e.Unique,
			references:  e.References,
		}
		// Nullable when: not PK, not notNull, not a timestamp, and is a nullable-capable type.
		f.nullable = !f.isPK && !f.notNull && !f.isTimestamp && isNullablePlanType(e.Type)
		fields = append(fields, f)
	}
	return fields
}

// planFieldGoType maps a PlanEntityField.Type to the Go type used in Values/Scan.
func planFieldGoType(t string) string {
	// Handle repeated types → pq arrays (e.g. "repeated string" → "pq.StringArray")
	if base, ok := strings.CutPrefix(t, "repeated "); ok {
		switch base {
		case "string":
			return "pq.StringArray"
		case "int32", "int64":
			return "pq.Int64Array"
		case "bool":
			return "pq.BoolArray"
		case "float", "float32", "double", "float64":
			return "pq.Float64Array"
		default:
			return "pq.StringArray"
		}
	}
	switch t {
	case "string":
		return "string"
	case "int32":
		return "int32"
	case "int64":
		return "int64"
	case "uint32":
		return "uint32"
	case "uint64":
		return "uint64"
	case "bool":
		return "bool"
	case "float", "float32":
		return "float32"
	case "double", "float64":
		return "float64"
	case "bytes":
		return "[]byte"
	case "google.protobuf.Timestamp", "timestamp":
		return "*timestamppb.Timestamp"
	default:
		return "string"
	}
}

// planFieldOrmType maps a PlanEntityField.Type to the orm.TypeXxx constant string
// used in generated Schema() code.
func planFieldOrmType(t string) string {
	// Repeated types use JSONB for ORM schema (works for both Postgres and SQLite)
	if strings.HasPrefix(t, "repeated ") {
		return "orm.TypeJSONB"
	}
	switch t {
	case "string":
		return "orm.TypeText"
	case "bool":
		return "orm.TypeBoolean"
	case "int32":
		return "orm.TypeInteger"
	case "int64":
		return "orm.TypeBigInt"
	case "uint32":
		return "orm.TypeInteger"
	case "uint64":
		return "orm.TypeBigInt"
	case "float", "float32", "double", "float64":
		return "orm.TypeText"
	case "bytes":
		return "orm.TypeBytea"
	case "google.protobuf.Timestamp", "timestamp":
		return "orm.TypeTimestampTZ"
	default:
		return "orm.TypeText"
	}
}

// isNullablePlanType returns true if the plan field type is a Go type that
// should be scanned as a pointer when the column is nullable.
func isNullablePlanType(t string) bool {
	// Repeated types are already reference types (pq.StringArray etc.), not nullable.
	if strings.HasPrefix(t, "repeated ") {
		return false
	}
	switch t {
	case "string", "int32", "int64", "uint32", "uint64", "bool", "float", "float32", "double", "float64":
		return true
	default:
		return false
	}
}